import { Router } from 'express';
import { WorkspaceController } from './workspace.controller.js';
import { authMiddleware } from '../../common/middlewares/auth.middleware.js';
import { requireWorkspaceRole } from '../../common/middlewares/requireWorkspaceRole.middleware.js';
import { WorkspaceService } from './workspace.service.js';
import { EmailService } from '../mail/mail.service.js';
import { WorkspaceRepo } from './workspace.repo.js';
import { AuthRepo } from '../auth/auth.repo.js';
import { ActivityService } from '../activity/activity.service.js';
import { prisma } from '../../db/prisma.js';
import { ActivityRepo } from '../activity/activity.repo.js';
import { validateBody, validateParams, validateQuery } from '../../common/middlewares/validateRequest.middleware.js';
import { acceptBodySchema, createBodySchema, inviteBodySchema, removeMemberBodySchema, updateBodySchema, } from './workspace.schemas.js';
import { ProjectRepo } from '../project/project.repo.js';
import { emptyBodySchema, paginationQuerySchema, workspaceParamsSchema } from '../../common/schemas/common.schemas.js';
const router = Router();
const workspaceController = new WorkspaceController(new WorkspaceService(new EmailService(), new WorkspaceRepo(prisma), new AuthRepo(prisma), new ProjectRepo(prisma), new ActivityService(new ActivityRepo()), prisma));
router.post('', authMiddleware, validateBody(createBodySchema), workspaceController.create);
router.get('', authMiddleware, validateBody(emptyBodySchema), validateQuery(paginationQuerySchema), workspaceController.getByUserId);
